import{_ as e,o as n,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"89. Definitions","description":"","frontmatter":{"title":"89. Definitions","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mspp/accident-pay-allowances/89-definitions.md","filePath":"ebas/mspp/accident-pay-allowances/89-definitions.md"}'),s={name:"ebas/mspp/accident-pay-allowances/89-definitions.md"};function a(r,t,p,c,l,d){return n(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="_89-definitions" tabindex="-1">89. Definitions <a class="header-anchor" href="#_89-definitions" aria-label="Permalink to &quot;89. Definitions&quot;">​</a></h1><p><strong>a.</strong> Disability has the same meaning as section 4 of the Equal Opportunity Act 2010 (Vic) (EO Act) and includes:</p><p><strong>(i)</strong> total or partial loss of a bodily function; or</p><p><strong>(ii)</strong> presence in the body of organisms that may cause disease;</p><p><strong>(iii)</strong> total or partial loss of a part of the body; or</p><p><strong>(iv)</strong> malfunction of a part of the body including a mental or psychological disease or disorder or condition or disorder that results in a person learning more slowly than those without the condition or disorder.</p><p><strong>b.</strong> Reasonable adjustments has the same meaning as section 20 of the EO Act and requires consideration of all relevant facts and circumstances including:</p><p><strong>(i)</strong> the Employee’s circumstances, including the nature of the disability;</p><p><strong>(ii)</strong> the nature of the Employee’s role;</p><p><strong>(iii)</strong> the nature of the adjustment required to accommodate the Employee’s disability;</p><p><strong>(iv)</strong> the financial circumstances of the Employer;</p><p><strong>(v)</strong> the size and nature of the workplace and the Employer’s business;</p><p><strong>(vi)</strong> the effect on the workplace and the Employer’s business of making the adjustment including the financial impact, the number of persons who would benefit or be disadvantaged and the impact of efficiency and productivity;</p><p><strong>(vii)</strong> the consequences for the Employer in making the adjustment,</p><p><strong>(viii)</strong> the consequences for the Employee in not making the adjustment.</p><p>Plain language terms: glossary, meanings.</p>',16)])])}const f=e(s,[["render",a]]);export{m as __pageData,f as default};
